// ---- math.js ----
export const PI = 3.14159;
export const E = 2.71828;

export function add(a, b) {
  return a + b;
}

export function multiply(a, b) {
  return a * b;
}

// Inline exports — can export any declaration

// ---- app.js ----
import { add, multiply, PI } from './math.js';

console.log(add(2, 3));        // 5
console.log(multiply(4, 5));   // 20
console.log(PI);               // 3.14159

// Renaming imports
import { add as sum, PI as pi } from './math.js';
console.log(sum(1, 2));  // 3

// Import all as a namespace
import * as MathUtils from './math.js';
console.log(MathUtils.add(1, 2));      // 3
console.log(MathUtils.PI);             // 3.14159

// ---- User.js ----
export default class User {
  constructor(name, email) {
    this.name = name;
    this.email = email;
  }

  getDisplayName() {
    return this.name + ' &lt;' + this.email + '&gt;';
  }
}

// Named helper alongside default
export function validateEmail(email) {
  return email.includes('@');
}

// ---- app.js ----
// Import default (any name) + named (must match)
import User, { validateEmail } from './User.js';

const user = new User('Alice', 'alice@example.com');
console.log(user.getDisplayName());
// 'Alice <alice@example.com>'

console.log(validateEmail('test@test.com')); // true

// Default import can be renamed freely:
import MyUser from './User.js';  // also works

// But named imports must match:
// import { validate } from './User.js'; // ERROR!

// ---- shapes/circle.js ----
export const PI = 3.14159;
export function area(radius) {
  return PI * radius * radius;
}

// ---- shapes/square.js ----
export function area(side) {
  return side * side;
}

// ---- shapes/index.js (barrel file) ----
export { area as circleArea, PI } from './circle.js';
export { area as squareArea } from './square.js';

// ---- app.js ----
import { circleArea, squareArea, PI } from './shapes/index.js';

console.log(circleArea(5));  // 78.53975
console.log(squareArea(4));  // 16
console.log(PI);             // 3.14159

// Or re-export everything:
// export * from './circle.js';
// export * from './square.js';
// (caution: name conflicts are silently dropped or cause errors)

// ---- heavy-chart.js ----
export default function renderChart(data) {
  // Expensive chart rendering logic
  console.log('Rendering chart with', data.length, 'points');
  return 'Chart rendered';
}

export function formatData(raw) {
  return raw.map(function(item) { return { x: item.x, y: item.y }; });
}

// ---- app.js ----
const button = document.getElementById('load-chart');

button.addEventListener('click', async function() {
  // Dynamic import — loads the module only on click
  try {
    const chartModule = await import('./heavy-chart.js');

    // Default export is on .default
    const renderChart = chartModule.default;
    // Named exports are regular properties
    const { formatData } = chartModule;

    const rawData = [{ x: 1, y: 2 }, { x: 3, y: 4 }];
    const formatted = formatData(rawData);
    const result = renderChart(formatted);
    console.log(result);
  } catch (err) {
    console.error('Failed to load chart module:', err);
  }
});

// Dynamic imports enable smaller initial bundle sizes
// and faster page loads — the browser only loads
// heavy-chart.js when the user clicks the button

